import { useEffect, useState } from "react"

import Navbar from "../Navbar"

import { toast } from "react-toastify"

import BASE_URL from "../../services/api"

import "./index.css"

const CreateProposal = () => {

    const [departments, setDepartments] =
        useState([])

    const [formData, setFormData] =
        useState({
            title: "",
            description: "",
            category: "",
            proposed_date: "",
            venue: "",
            estimated_budget: "",
            expected_audience: "",
            department_id: "",
            document_link: ""
        })

         useEffect(() => {

        getDepartments()

    }, [])

    const getDepartments = async () => {

        try {

            const response = await fetch(
                `${BASE_URL}/departments`
            )

            const data =
                await response.json()

            setDepartments(data)

        } catch (error) {

            toast.error(
                "Failed to fetch departments"
            )
        }
    }

     const handleChange = (e) => {

        setFormData({
            ...formData,
            [e.target.name]: e.target.value
        })
    }

    const handleSubmit = async (e) => {

        e.preventDefault()

        try {

            const token =
                localStorage.getItem("token")

            const response = await fetch(
                `${BASE_URL}/events`,
                {
                    method: "POST",

                    headers: {
                        "Content-Type":
                        "application/json",

                        Authorization:
                        `Bearer ${token}`
                    },
                     body: JSON.stringify(formData)
                }
            )

            const data =
                await response.json()

            if (!response.ok) {

                toast.error(data.error)

                return
            }

            toast.success(
                "Proposal created"
            )
             setFormData({
                title: "",
                description: "",
                category: "",
                proposed_date: "",
                venue: "",
                estimated_budget: "",
                expected_audience: "",
                department_id: "",
                document_link: ""
            })

        } catch {

            toast.error(
                "Failed to create proposal"
            )
        }
    }

    return (
        <div>
            <h1>CreateProposal Page</h1>
        </div>
    )
}

export default CreateProposal
